import React, { useState, useRef, useEffect } from "react";

// ─── Defaults (used only on first run; afterwards loaded from storage) ──
const DEFAULT_SERVICES = [
  { id: "s1", name: "The Classic", price: 200, desc: "Haircut + Neck Shave + Powder" },
  { id: "s2", name: "The Fresh Fade", price: 300, desc: "Haircut + Shampoo + Blow Dry + Line-up" },
  { id: "s3", name: "The Full Reset", price: 400, desc: "Haircut + Hot Towel Face Shave + Neck Clean-up + Styling + Powder" },
  { id: "s4", name: "The Gentleman", price: 350, desc: "Haircut + Shampoo + Beard Trim/Shape + Pomade Styling" },
  { id: "s5", name: "The Executive", price: 500, desc: "Haircut + Shampoo + Scalp Massage + Hot Towel + Scalp Treatment + Styling" },
  { id: "s6", name: "The Clean Shave", price: 120, desc: "Hot Towel + Lather + Straight Razor Shave + Aftershave" },
  { id: "s7", name: "The Lining", price: 50, desc: "Neck Shave + Sideburns Clean-up" },
  { id: "s8", name: "Head Shave / Kalbo", price: "200-300", desc: "Full Head Shave + Hot Towel + Aftershave" },
  { id: "s9", name: "Ladies' Cut", price: 350, desc: "Wash + Haircut + Blow Dry + Light Styling" },
];
const DEFAULT_BARBERS = ["Jhan", "JM", "Efren"];
// Owner account ships with the app; staff are created inside the panel.
const DEFAULT_USERS = [{ user: "owner", pass: "fade2014", role: "owner", name: "Owner" }];
// Payment methods — owner can toggle on/off and edit details in the admin panel.
const DEFAULT_PAYMENTS = {
  gcash: { on: true, label: "GCash / InstaPay", name: "RE***R S.", number: "0931 069 ••••" },
  bank: { on: true, label: "Bank Transfer", bankName: "BDO", accName: "Fade Republic Barbershop", accNumber: "0000 0000 0000" },
  cash: { on: true, label: "Cash (pay at shop)" },
  crypto: { on: true, label: "Crypto", network: "USDT (TRC20)", address: "Tap edit to add your wallet address" },
};
// Online reservation fee — added on top of the service price for online bookings. Walk-ins pay none.
const DEFAULT_FEE = { on: true, amount: 30 };

const SLOTS = ["7:30 AM","8:30 AM","9:30 AM","10:30 AM","11:30 AM","1:00 PM","2:00 PM","3:00 PM","4:00 PM","5:00 PM","6:00 PM","7:00 PM","8:00 PM"];
const GCASH_NAME = "RE***R S.";
const GCASH_NUM = "0931 069 ••••";
const WELCOME = "Welcome to FADE REPUBLIC! Clean cuts, sharp fades. 🇵🇭\n\nKumusta po! Anong service po ang gusto ninyo, at kanino kayo gustong magpa-gupit? You can chat in Tagalog, English, or Taglish — bahala kayo! ✂️";
const GCASH_QR = "data:image/png;base64,";

const sysPrompt = (services, barbers, bookings, fee) => {
  const taken = bookings.filter((b) => b.barber !== "Any available").map((b) => `${b.barber} is booked ${b.day} at ${b.time}`).join("; ") || "no bookings yet";
  const menu = services.map((s, i) => `${i + 1}. ${s.name} ₱${s.price} — ${s.desc}`).join("\n");
  return `You are "Republic", the booking concierge for FADE REPUBLIC BARBERSHOP in Brgy. San Roque, Sto. Tomas, Batangas. Open daily 7:30AM–9PM. Payment: cash or GCash.
Tagline: "Clean cuts. Sharp fades. Real confidence."
Sharp, confident, friendly, efficient. Keep replies SHORT (1-3 sentences). Use pesos (₱).

LANGUAGE: Detect the customer's language from THEIR message and reply in the SAME language — Tagalog/Filipino, English, or Taglish. If they greet you in Tagalog, answer in natural conversational Tagalog/Taglish like a real Filipino barber ("Sige po! Anong service po?"). Match their formality (po/opo). Keep service NAMES in English. Default to friendly Taglish if unsure.

SERVICES:
${menu}

BARBERS: ${barbers.join(", ")}, or "Any available".
TIME SLOTS (pick one): ${SLOTS.join(", ")}.
CURRENT BOOKINGS: ${taken}.
${fee?.on ? `RESERVATION FEE: An online booking fee of ₱${fee.amount} is added ON TOP of the service price for all online bookings (walk-ins pay no fee). If a customer asks the price, mention the service price and that a ₱${fee.amount} reservation fee applies online. Do not add it into the "price" — the app handles the total at checkout.` : "RESERVATION FEE: none."}

If a customer asks for a barber+day+time already booked above, say it's taken and offer the nearest open slot or another barber. Do NOT confirm a conflicting slot.

Collect, in any order: 1. service 2. barber 3. day (today, tomorrow, weekday, or an exact date like "Jun 5, 2026") 4. time (one of the slots) 5. first name 6. mobile number. Ask only for what's missing. Always get a mobile number before confirming. If the customer gives an exact date (e.g. "Jun 5, 2026"), keep that EXACT date string in the "day" field — do not reword it.

Once you have ALL SIX and there is no conflict, confirm in one tidy line and END that message with a single line in EXACTLY this format on its own line:
BOOKING_CONFIRMED: {"service":"...","barber":"...","day":"...","time":"...","name":"...","phone":"..."}

Only emit BOOKING_CONFIRMED when everything's gathered, conflict-free, and unchanged. Never invent prices. Never mention you are an AI.`;
};

export default function FadeRepublic() {
  const [view, setView] = useState("book");
  const [services, setServices] = useState(DEFAULT_SERVICES);
  const [barbers, setBarbers] = useState(DEFAULT_BARBERS);
  const [users, setUsers] = useState(DEFAULT_USERS);
  const [payments, setPayments] = useState(DEFAULT_PAYMENTS);
  const [fee, setFee] = useState(DEFAULT_FEE);
  const [bookings, setBookings] = useState([]);
  const [session, setSession] = useState(null); // {user, role, name}
  const [hydrated, setHydrated] = useState(false);
  const [payFor, setPayFor] = useState(null);
  const [justBooked, setJustBooked] = useState(false);
  const [showCal, setShowCal] = useState(false);

  const [messages, setMessages] = useState([{ role: "assistant", content: WELCOME }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef(null);

  // ── Load all shared data on mount ──
  useEffect(() => {
    (async () => {
      try {
        const r = await window.storage.get("shopdata", true);
        if (r && r.value) {
          const d = JSON.parse(r.value);
          if (d.services) setServices(d.services);
          if (d.barbers) setBarbers(d.barbers);
          if (d.users) setUsers(d.users);
          if (d.payments) setPayments(d.payments);
          if (d.fee) setFee(d.fee);
          if (d.bookings) setBookings(d.bookings);
        }
      } catch {}
      finally { setHydrated(true); }
    })();
  }, []);

  // ── Persist everything together ──
  useEffect(() => {
    if (!hydrated) return;
    window.storage.set("shopdata", JSON.stringify({ services, barbers, users, payments, fee, bookings }), true).catch(() => {});
  }, [services, barbers, users, payments, fee, bookings, hydrated]);

  useEffect(() => { scrollRef.current?.scrollTo({ top: 99999, behavior: "smooth" }); }, [messages, loading]);

  const peso = (p) => `₱${p}`;
  const priceFor = (svc) => { if (!svc) return ""; const s = services.find((x) => svc.toLowerCase().includes(x.name.toLowerCase())); return s ? s.price : ""; };
  const isTaken = (barber, day, time) => barber !== "Any available" && bookings.some((b) => b.barber === barber && b.day?.toLowerCase() === day?.toLowerCase() && b.time === time);
  const parseBooking = (text) => { const m = text.match(/BOOKING_CONFIRMED:\s*(\{.*\})/s); if (!m) return null; try { return JSON.parse(m[1]); } catch { return null; } };

  const send = async (forced) => {
    const text = (forced ?? input).trim();
    if (!text || loading) return;
    const next = [...messages, { role: "user", content: text }];
    setMessages(next); setInput(""); setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system: sysPrompt(services, barbers, bookings, fee), messages: next.map((m) => ({ role: m.role, content: m.content })) }),
      });
      const data = await res.json();
      let reply = data.content.map((c) => (c.type === "text" ? c.text : "")).join("\n");
      const booking = parseBooking(reply);
      reply = reply.replace(/BOOKING_CONFIRMED:\s*\{.*\}/s, "").trim();
      if (booking && isTaken(booking.barber, booking.day, booking.time)) {
        setMessages((prev) => [...prev, { role: "assistant", content: `Ay pasensya — si ${booking.barber} po ay naka-book na sa ${booking.day} ng ${booking.time}. Gusto ninyo ng ibang oras o ibang barber? (That slot was just taken.)` }]);
      } else {
        setMessages((prev) => [...prev, { role: "assistant", content: reply }]);
        if (booking) { const record = { ...booking, id: Date.now(), price: priceFor(booking.service) }; setBookings((prev) => [...prev, record]); setPayFor(record); }
      }
    } catch {
      setMessages((prev) => [...prev, { role: "assistant", content: "Pasensya po, na-disconnect sandali. Pwede pong ulitin? (Sorry, connection dropped.)" }]);
    } finally { setLoading(false); }
  };

  const chip = (label) => send(label);
  const removeBooking = (id) => setBookings((prev) => prev.filter((b) => b.id !== id));
  const closePay = (paid) => {
    if (payFor) {
      if (paid) {
        setBookings((prev) => prev.map((b) => (b.id === payFor.id ? { ...b, paid: true } : b)));
        setMessages((prev) => [...prev, { role: "assistant", content: `Salamat po, ${payFor.name}! Na-receive na ang booking ninyo at payment. 🪒\n\n📸 Pakipakita po ang screenshot ng receipt pagdating sa shop. Kita-kita po tayo!\n\n👉 Tap "New Booking" below para sa susunod na customer.` }]);
      } else {
        setMessages((prev) => [...prev, { role: "assistant", content: `Sige po, ${payFor.name} — naka-book na kayo! Bayad na lang po sa shop pagdating. Kita-kita po tayo! 🪒\n\n👉 Tap "New Booking" below para sa susunod na customer.` }]);
      }
      setJustBooked(true);
    }
    setPayFor(null);
  };

  const newBooking = () => {
    setMessages([{ role: "assistant", content: WELCOME }]);
    setInput("");
    setJustBooked(false);
  };

  const barberStatus = (b) => {
    const count = bookings.filter((x) => x.barber === b).length;
    if (count === 0) return { label: "AVAILABLE", color: "#5ec46a" };
    if (count < 3) return { label: `${count} BOOKED`, color: GOLD };
    return { label: "FULLY BOOKED", color: "#e0564b" };
  };

  return (
    <div style={S.root}>
      <style>{css}</style>

      {/* ── Sidebar ── */}
      <aside style={S.aside}>
        <div style={S.brandWrap}>
          <div style={S.crown}>♛</div>
          <h1 style={S.brand}>FADE<br />REPUBLIC</h1>
          <p style={S.tag}>BARBERSHOP</p>
          <p style={S.slogan}>CUT · FADE · STYLE</p>
        </div>

        <div style={S.toggle}>
          <button style={{ ...S.tBtn, ...(view === "book" ? S.tOn : {}) }} onClick={() => setView("book")}>Book</button>
          <button style={{ ...S.tBtn, ...(view === "admin" ? S.tOn : {}) }} onClick={() => setView("admin")}>Admin {session ? "🔓" : "🔒"}</button>
        </div>

        <div style={S.menuTitle}>THE CHAIRS — LIVE</div>
        <div style={S.chairList}>
          {barbers.map((b) => {
            const st = barberStatus(b);
            return (
              <div key={b} style={S.chairRow} onClick={() => view === "book" && chip(`Book me with ${b}`)}>
                <span style={S.chairName}>{b}</span>
                <span style={{ ...S.statusPill, color: st.color, borderColor: st.color }}><span style={{ ...S.miniDot, background: st.color }} /> {st.label}</span>
              </div>
            );
          })}
        </div>

        {view === "book" && (
          <>
            <div style={{ ...S.menuTitle, marginTop: 24 }}>PRICE LIST</div>
            <ul style={S.menu}>
              {services.map((s, i) => (
                <li key={s.id} style={S.menuItem} onClick={() => chip(`I'd like ${s.name}`)}>
                  <div style={S.menuTop}><span style={S.menuName}><span style={S.num}>{i + 1}</span> {s.name}</span><span style={S.menuPrice}>{peso(s.price)}</span></div>
                  <div style={S.menuDesc}>{s.desc}</div>
                </li>
              ))}
            </ul>
          </>
        )}

        <div style={S.info}>📍 Brgy. San Roque, Sto. Tomas, Batangas<br />🕖 Open daily 7:30AM–9PM<br />💳 Cash &amp; GCash accepted</div>
      </aside>

      {/* ── Main ── */}
      {view === "book" ? (
        <main style={S.chatCol}>
          <div style={S.chatHead}>
            <span style={S.dot} /> REPUBLIC IS IN — BOOKING NOW
            {messages.length > 1 && !justBooked && <button style={S.lockBtn} onClick={newBooking}>↺ Reset</button>}
          </div>
          <div ref={scrollRef} style={S.thread}>
            {messages.map((m, i) => (
              <div key={i} style={{ ...S.rowB, justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}>
                <div style={{ ...S.bubble, ...(m.role === "user" ? S.userB : S.botB) }}>{m.content}</div>
              </div>
            ))}
            {loading && <div style={S.rowB}><div style={{ ...S.bubble, ...S.botB }}><span className="typing"><i /> <i /> <i /></span></div></div>}
          </div>
          {messages.length < 3 && !justBooked && (
            <div style={S.quick}>{["Pwede magpa-fade bukas?", "The Gentleman kay Jhan", "Anong pinakamaaga ngayon?"].map((q) => <button key={q} style={S.quickBtn} onClick={() => chip(q)}>{q}</button>)}</div>
          )}
          {showCal && !justBooked && (
            <CalendarPicker barbers={barbers} bookings={bookings} onPick={(msg) => { setShowCal(false); chip(msg); }} onClose={() => setShowCal(false)} />
          )}
          {justBooked ? (
            <div style={S.doneRow}>
              <div style={S.doneCheck}>✓ Booking complete</div>
              <button style={S.newBookingBtn} onClick={newBooking}>➕ New Booking · Bagong Customer</button>
            </div>
          ) : (
            <div style={S.inputRow}>
              <button style={{ ...S.calToggle, ...(showCal ? S.calToggleOn : {}) }} onClick={() => setShowCal((v) => !v)} title="Pick date & time">📅</button>
              <input style={S.input} value={input} placeholder="Mag-type po dito… (Tagalog or English)" onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === "Enter" && send()} disabled={loading} />
              <button style={S.sendBtn} onClick={() => send()} disabled={loading}>↑</button>
            </div>
          )}
        </main>
      ) : !session ? (
        <LoginScreen users={users} onLogin={setSession} onBack={() => setView("book")} />
      ) : (
        <AdminPanel
          session={session} bookings={bookings} services={services} barbers={barbers} users={users} payments={payments}
          peso={peso} onRemove={removeBooking}
          setServices={setServices} setBarbers={setBarbers} setUsers={setUsers} setPayments={setPayments}
          fee={fee} setFee={setFee}
          onLogout={() => { setSession(null); setView("book"); }}
        />
      )}

      {/* ── Payment modal (multi-method) ── */}
      {payFor && (
        <PaymentModal booking={payFor} payments={payments} fee={fee} peso={peso} qr={GCASH_QR} onPaid={() => closePay(true)} onLater={() => closePay(false)} />
      )}
    </div>
  );
}

// ─── Calendar picker (date + time with live availability) ─────────
function CalendarPicker({ barbers, bookings, onPick, onClose }) {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const [viewMonth, setViewMonth] = useState(new Date(today.getFullYear(), today.getMonth(), 1));
  const [date, setDate] = useState(null);
  const [barber, setBarber] = useState("Any available");

  const fmt = (d) => d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" });
  const key = (d) => d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });

  const slotTaken = (d, time) => {
    if (barber === "Any available") {
      // taken only if every named barber is booked at that time on that date
      return barbers.length > 0 && barbers.every((b) => bookings.some((x) => x.barber === b && x.day === key(d) && x.time === time));
    }
    return bookings.some((x) => x.barber === barber && x.day === key(d) && x.time === time);
  };

  const y = viewMonth.getFullYear(), m = viewMonth.getMonth();
  const firstDay = new Date(y, m, 1).getDay();
  const daysInMonth = new Date(y, m + 1, 0).getDate();
  const cells = [];
  for (let i = 0; i < firstDay; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(new Date(y, m, d));

  const canGoBack = viewMonth > new Date(today.getFullYear(), today.getMonth(), 1);
  const monthLabel = viewMonth.toLocaleDateString("en-US", { month: "long", year: "numeric" });

  return (
    <div style={S.calPanel}>
      <div style={S.calTop}>
        <span style={S.calTitle}>📅 Pick a date &amp; time</span>
        <button style={S.calClose} onClick={onClose}>✕</button>
      </div>

      <div style={S.calBarberRow}>
        <span style={S.calBarberLbl}>Barber:</span>
        {["Any available", ...barbers].map((b) => (
          <button key={b} style={{ ...S.calBarberPill, ...(barber === b ? S.calBarberOn : {}) }} onClick={() => { setBarber(b); }}>{b}</button>
        ))}
      </div>

      {!date ? (
        <>
          <div style={S.calNav}>
            <button style={{ ...S.calArrow, opacity: canGoBack ? 1 : 0.3 }} onClick={() => canGoBack && setViewMonth(new Date(y, m - 1, 1))}>‹</button>
            <span style={S.calMonth}>{monthLabel}</span>
            <button style={S.calArrow} onClick={() => setViewMonth(new Date(y, m + 1, 1))}>›</button>
          </div>
          <div style={S.calGrid}>
            {["S", "M", "T", "W", "T", "F", "S"].map((d, i) => <div key={i} style={S.calDow}>{d}</div>)}
            {cells.map((d, i) => {
              if (!d) return <div key={i} />;
              const past = d < today;
              const isToday = d.getTime() === today.getTime();
              return (
                <button key={i} disabled={past} style={{ ...S.calDay, ...(past ? S.calDayPast : {}), ...(isToday ? S.calDayToday : {}) }} onClick={() => !past && setDate(d)}>{d.getDate()}</button>
              );
            })}
          </div>
        </>
      ) : (
        <>
          <div style={S.calBackRow}>
            <button style={S.calBack} onClick={() => setDate(null)}>‹ Back</button>
            <span style={S.calChosen}>{fmt(date)}</span>
          </div>
          <div style={S.slotGrid}>
            {SLOTS.map((t) => {
              const taken = slotTaken(date, t);
              return (
                <button key={t} disabled={taken} style={{ ...S.slotBtn, ...(taken ? S.slotTaken : {}) }}
                  onClick={() => !taken && onPick(`I'd like to book ${barber === "Any available" ? "" : "with " + barber + " "}on ${key(date)} at ${t}`)}>
                  {t}{taken ? <span style={S.slotX}> · booked</span> : ""}
                </button>
              );
            })}
          </div>
          <p style={S.calHint}>Greyed-out times are already booked{barber !== "Any available" ? ` for ${barber}` : ""}. Tap an open slot to continue.</p>
        </>
      )}
    </div>
  );
}

// ─── Payment modal (customer picks an enabled method) ─────────────
function PaymentModal({ booking, payments, fee, peso, qr, onPaid, onLater }) {
  const enabled = Object.entries(payments).filter(([, v]) => v.on).map(([k]) => k);
  const [method, setMethod] = useState(enabled[0] || "cash");
  const [copied, setCopied] = useState("");
  const copy = (text, tag) => { try { navigator.clipboard.writeText(text); setCopied(tag); setTimeout(() => setCopied(""), 1500); } catch {} };
  const icon = { gcash: "G", bank: "🏦", cash: "💵", crypto: "₿" };

  const basePrice = typeof booking.price === "number" ? booking.price : null;
  const feeAmt = fee?.on ? (fee.amount || 0) : 0;
  const total = basePrice != null ? basePrice + feeAmt : null;

  return (
    <div style={S.overlay} onClick={onLater}>
      <div style={S.modal} onClick={(e) => e.stopPropagation()}>
        <div style={S.payHead}>Confirm &amp; Pay</div>
        <p style={S.modalSub}>Booking confirmed for <strong>{booking.name}</strong></p>
        <div style={S.modalLine}>{booking.service} · {booking.barber}</div>
        <div style={S.modalLine}>{booking.day} — {booking.time}</div>

        {total != null ? (
          <div style={S.breakdown}>
            <div style={S.brkRow}><span>Service</span><span>{peso(basePrice)}</span></div>
            {feeAmt > 0 && <div style={S.brkRow}><span>Reservation fee</span><span>+{peso(feeAmt)}</span></div>}
            <div style={S.brkTotal}><span>Total to pay</span><span>{peso(total)}</span></div>
          </div>
        ) : (
          <div style={S.amount}>{feeAmt > 0 ? `${peso(feeAmt)} reservation fee` : "Pay at shop"}</div>
        )}

        {/* method tabs */}
        <div style={S.payTabs}>
          {enabled.map((k) => (
            <button key={k} style={{ ...S.payTab, ...(method === k ? S.payTabOn : {}) }} onClick={() => setMethod(k)}>
              <span style={S.payTabIcon}>{icon[k]}</span>{payments[k].label.split(" ")[0]}
            </button>
          ))}
        </div>

        <div style={S.payBody}>
          {method === "gcash" && (
            <>
              <div style={S.qr}><img src={qr} alt="GCash InstaPay QR" style={S.qrImg} /></div>
              <p style={S.qrHint}>I-scan gamit ang GCash o anumang InstaPay app</p>
              <p style={S.gcashName}>{payments.gcash.name}</p>
              <p style={S.gcashNum}>Mobile No.: {payments.gcash.number}</p>
            </>
          )}
          {method === "bank" && (
            <div style={S.detailBox}>
              <Row label="Bank" value={payments.bank.bankName} />
              <Row label="Account Name" value={payments.bank.accName} />
              <Row label="Account No." value={payments.bank.accNumber} onCopy={() => copy(payments.bank.accNumber, "bank")} copied={copied === "bank"} />
            </div>
          )}
          {method === "crypto" && (
            <div style={S.detailBox}>
              <Row label="Network" value={payments.crypto.network} />
              <Row label="Wallet Address" value={payments.crypto.address} onCopy={() => copy(payments.crypto.address, "crypto")} copied={copied === "crypto"} small />
              <p style={S.cryptoWarn}>⚠️ Send the exact ₱ equivalent. Network fees apply.</p>
            </div>
          )}
          {method === "cash" && (
            <div style={S.detailBox}><p style={S.cashNote}>Bayad po sa shop pagdating ninyo. No advance payment needed. (Pay at the shop on arrival.)</p></div>
          )}
        </div>

        {method !== "cash" && <p style={S.receiptNote}>📸 I-screenshot po ang receipt para sa verification</p>}

        <div style={S.modalBtns}>
          {method === "cash"
            ? <button style={S.payDone} onClick={onLater}>Got it — see you at the shop</button>
            : <button style={S.payDone} onClick={onPaid}>I've paid via {payments[method].label.split(" ")[0]}</button>}
          {method !== "cash" && <button style={S.payLater} onClick={onLater}>I'll pay at the shop instead</button>}
        </div>
      </div>
    </div>
  );
}
const Row = ({ label, value, onCopy, copied, small }) => (
  <div style={S.detailRow}>
    <span style={S.detailLabel}>{label}</span>
    <span style={{ ...S.detailValue, fontSize: small ? 12 : 14 }}>{value}{onCopy && <button style={S.copyBtn} onClick={onCopy}>{copied ? "✓" : "Copy"}</button>}</span>
  </div>
);

// ─── Login ─────────────────────────────────────────────────────────
function LoginScreen({ users, onLogin, onBack }) {
  const [u, setU] = useState("");
  const [p, setP] = useState("");
  const [err, setErr] = useState("");
  const tryLogin = () => {
    const found = users.find((x) => x.user.toLowerCase() === u.trim().toLowerCase() && x.pass === p);
    if (found) onLogin({ user: found.user, role: found.role, name: found.name || found.user });
    else setErr("Maling username o password.");
  };
  return (
    <main style={S.lockCol}>
      <div style={S.lockBox}>
        <div style={S.lockIcon}>🔒</div>
        <h2 style={S.lockTitle}>STAFF LOGIN</h2>
        <p style={S.lockSub}>Fade Republic — admin access</p>
        <input style={S.loginInput} placeholder="Username" value={u} onChange={(e) => { setU(e.target.value); setErr(""); }} />
        <input style={S.loginInput} placeholder="Password" type="password" value={p} onChange={(e) => { setP(e.target.value); setErr(""); }} onKeyDown={(e) => e.key === "Enter" && tryLogin()} />
        {err && <p style={S.pinErr}>{err}</p>}
        <button style={S.loginBtn} onClick={tryLogin}>Log In</button>
        <button style={S.lockBack} onClick={onBack}>← Back to booking</button>
        <p style={S.loginNote}>Staff accounts are created by the owner inside the panel. No public sign-up.</p>
      </div>
    </main>
  );
}

// ─── Admin panel (tabbed) ──────────────────────────────────────────
function AdminPanel({ session, bookings, services, barbers, users, payments, peso, onRemove, setServices, setBarbers, setUsers, setPayments, fee, setFee, onLogout }) {
  const isOwner = session.role === "owner";
  const [tab, setTab] = useState("appts");
  const tabs = isOwner ? ["appts", "reports", "barbers", "services", "payments", "staff"] : ["appts", "reports"];
  const labels = { appts: "Appointments", reports: "Reports", barbers: "Barbers", services: "Services", payments: "Payments", staff: "Staff" };

  return (
    <main style={S.adminCol}>
      <div style={S.chatHead}>
        <span style={{ ...S.dot, background: "#5ec46a" }} /> ADMIN — {session.name.toUpperCase()} ({isOwner ? "OWNER" : "STAFF"})
        <button style={S.lockBtn} onClick={onLogout}>Log out</button>
      </div>

      <div style={S.adminTabs}>
        {tabs.map((t) => (
          <button key={t} style={{ ...S.adminTab, ...(tab === t ? S.adminTabOn : {}) }} onClick={() => setTab(t)}>{labels[t]}</button>
        ))}
      </div>

      <div style={S.adminBody}>
        {tab === "appts" && <ApptsTab bookings={bookings} barbers={barbers} peso={peso} onRemove={onRemove} />}
        {tab === "reports" && <ReportsTab bookings={bookings} barbers={barbers} peso={peso} />}
        {tab === "barbers" && isOwner && <BarbersTab barbers={barbers} setBarbers={setBarbers} />}
        {tab === "services" && isOwner && <ServicesTab services={services} setServices={setServices} peso={peso} />}
        {tab === "payments" && isOwner && <PaymentsTab payments={payments} setPayments={setPayments} fee={fee} setFee={setFee} peso={peso} />}
        {tab === "staff" && isOwner && <StaffTab users={users} setUsers={setUsers} session={session} />}
      </div>
    </main>
  );
}

function ApptsTab({ bookings, barbers, peso, onRemove }) {
  const revenue = bookings.reduce((s, b) => s + (typeof b.price === "number" ? b.price : 0), 0);
  const paidCount = bookings.filter((b) => b.paid).length;
  const cols = [...barbers, "Any available"];
  return (
    <>
      <div style={S.statsRow}>
        <Stat label="BOOKINGS" value={bookings.length} />
        <Stat label="GCASH PAID" value={paidCount} />
        <Stat label="EST. REVENUE" value={peso(revenue)} />
      </div>
      <div style={S.board}>
        {cols.map((b) => {
          const list = bookings.filter((x) => x.barber === b);
          if (b === "Any available" && list.length === 0) return null;
          return (
            <div key={b} style={S.chairColBoard}>
              <div style={S.chairHead}>{b === "Any available" ? "Unassigned" : b}<span style={S.chairCount}>{list.length}</span></div>
              {list.length === 0 ? <div style={S.empty}>No appointments</div> : list.map((a) => (
                <div key={a.id} style={S.apptCard}>
                  <div style={S.apptTime}>{a.day} · {a.time}</div>
                  <div style={S.apptName}>{a.name}</div>
                  <div style={S.apptSvc}>{a.service}</div>
                  {a.phone && <div style={S.apptPhone}>📱 {a.phone}</div>}
                  <div style={S.apptFoot}><span style={a.paid ? S.paid : S.unpaid}>{a.paid ? "✓ Paid" : `${a.price ? peso(a.price) : "—"} due`}</span><span style={S.del} onClick={() => onRemove(a.id)}>Cancel</span></div>
                </div>
              ))}
            </div>
          );
        })}
      </div>
    </>
  );
}

function BarbersTab({ barbers, setBarbers }) {
  const [name, setName] = useState("");
  const add = () => { const n = name.trim(); if (n && !barbers.includes(n)) { setBarbers([...barbers, n]); setName(""); } };
  return (
    <div style={S.manageWrap}>
      <h3 style={S.manageTitle}>Manage Barbers</h3>
      <p style={S.manageSub}>New barbers appear instantly in booking, availability, and the chair board.</p>
      <div style={S.addRow}>
        <input style={S.manageInput} placeholder="New barber's name" value={name} onChange={(e) => setName(e.target.value)} onKeyDown={(e) => e.key === "Enter" && add()} />
        <button style={S.addBtn} onClick={add}>+ Add</button>
      </div>
      <div style={S.list}>
        {barbers.map((b) => (
          <div key={b} style={S.listItem}><span style={S.listName}>{b}</span><button style={S.removeBtn} onClick={() => setBarbers(barbers.filter((x) => x !== b))}>Remove</button></div>
        ))}
      </div>
    </div>
  );
}

function ServicesTab({ services, setServices, peso }) {
  const [name, setName] = useState(""); const [price, setPrice] = useState(""); const [desc, setDesc] = useState("");
  const add = () => {
    const n = name.trim(); if (!n || !price) return;
    const pNum = /^\d+$/.test(String(price).trim()) ? parseInt(price, 10) : String(price).trim();
    setServices([...services, { id: "s" + Date.now(), name: n, price: pNum, desc: desc.trim() }]);
    setName(""); setPrice(""); setDesc("");
  };
  return (
    <div style={S.manageWrap}>
      <h3 style={S.manageTitle}>Manage Services</h3>
      <p style={S.manageSub}>Add new services as the business expands. Republic quotes these prices automatically.</p>
      <div style={S.svcForm}>
        <input style={S.manageInput} placeholder="Service name (e.g. Hair Color)" value={name} onChange={(e) => setName(e.target.value)} />
        <input style={{ ...S.manageInput, maxWidth: 130 }} placeholder="Price ₱" value={price} onChange={(e) => setPrice(e.target.value)} />
        <input style={S.manageInput} placeholder="What's included (optional)" value={desc} onChange={(e) => setDesc(e.target.value)} />
        <button style={S.addBtn} onClick={add}>+ Add</button>
      </div>
      <div style={S.list}>
        {services.map((s) => (
          <div key={s.id} style={S.listItem}>
            <div><span style={S.listName}>{s.name}</span> <span style={S.listPrice}>{peso(s.price)}</span><div style={S.listDesc}>{s.desc}</div></div>
            <button style={S.removeBtn} onClick={() => setServices(services.filter((x) => x.id !== s.id))}>Remove</button>
          </div>
        ))}
      </div>
    </div>
  );
}

function StaffTab({ users, setUsers, session }) {
  const [u, setU] = useState(""); const [p, setP] = useState(""); const [nm, setNm] = useState("");
  const [msg, setMsg] = useState("");
  const add = () => {
    const un = u.trim().toLowerCase();
    if (!un || !p) { setMsg("Username and password required."); return; }
    if (users.some((x) => x.user.toLowerCase() === un)) { setMsg("That username already exists."); return; }
    setUsers([...users, { user: un, pass: p, role: "staff", name: nm.trim() || un }]);
    setU(""); setP(""); setNm(""); setMsg("Staff account created.");
  };
  return (
    <div style={S.manageWrap}>
      <h3 style={S.manageTitle}>Staff Accounts</h3>
      <p style={S.manageSub}>You create each login — there is no public sign-up. Staff can view bookings but cannot edit barbers, services, or prices.</p>
      <div style={S.svcForm}>
        <input style={S.manageInput} placeholder="Display name" value={nm} onChange={(e) => setNm(e.target.value)} />
        <input style={S.manageInput} placeholder="Username" value={u} onChange={(e) => setU(e.target.value)} />
        <input style={S.manageInput} placeholder="Password" value={p} onChange={(e) => setP(e.target.value)} />
        <button style={S.addBtn} onClick={add}>+ Create</button>
      </div>
      {msg && <p style={S.staffMsg}>{msg}</p>}
      <div style={S.list}>
        {users.map((x) => (
          <div key={x.user} style={S.listItem}>
            <div><span style={S.listName}>{x.name || x.user}</span> <span style={S.roleTag}>{x.role}</span><div style={S.listDesc}>@{x.user}</div></div>
            {x.role !== "owner" ? <button style={S.removeBtn} onClick={() => setUsers(users.filter((y) => y.user !== x.user))}>Remove</button> : <span style={S.youTag}>{x.user === session.user ? "you" : "owner"}</span>}
          </div>
        ))}
      </div>
      <p style={S.securityNote}>⚠️ Demo note: passwords are stored in the app for this prototype. For real security, connect a backend that hashes passwords.</p>
    </div>
  );
}

// ─── Reports tab (Daily / Weekly / Monthly) ───────────────────────
function ReportsTab({ bookings, barbers, peso }) {
  const [period, setPeriod] = useState("day");
  const now = Date.now();
  const windows = { day: 86400000, week: 604800000, month: 2592000000 };
  // booking.id is the creation timestamp (Date.now()); fall back to including all if missing.
  const inPeriod = bookings.filter((b) => !b.id || now - b.id <= windows[period]);

  const revenue = inPeriod.reduce((s, b) => s + (typeof b.price === "number" ? b.price : 0), 0);
  const paid = inPeriod.filter((b) => b.paid);
  const paidRev = paid.reduce((s, b) => s + (typeof b.price === "number" ? b.price : 0), 0);
  const dueRev = revenue - paidRev;

  const byBarber = barbers.map((b) => {
    const list = inPeriod.filter((x) => x.barber === b);
    return { name: b, count: list.length, rev: list.reduce((s, x) => s + (typeof x.price === "number" ? x.price : 0), 0) };
  }).sort((a, b) => b.rev - a.rev);

  const svcCount = {};
  inPeriod.forEach((b) => { svcCount[b.service] = (svcCount[b.service] || 0) + 1; });
  const topServices = Object.entries(svcCount).sort((a, b) => b[1] - a[1]).slice(0, 5);
  const maxBarberRev = Math.max(1, ...byBarber.map((b) => b.rev));
  const label = { day: "Today", week: "This Week", month: "This Month" }[period];

  return (
    <div style={S.manageWrap}>
      <h3 style={S.manageTitle}>Reports</h3>
      <div style={S.reportToggle}>
        {["day", "week", "month"].map((p) => (
          <button key={p} style={{ ...S.reportBtn, ...(period === p ? S.reportBtnOn : {}) }} onClick={() => setPeriod(p)}>
            {{ day: "Daily", week: "Weekly", month: "Monthly" }[p]}
          </button>
        ))}
      </div>

      <div style={S.statsRow}>
        <Stat label={`BOOKINGS · ${label.toUpperCase()}`} value={inPeriod.length} />
        <Stat label="TOTAL VALUE" value={peso(revenue)} />
      </div>
      <div style={{ ...S.statsRow, paddingTop: 12 }}>
        <Stat label="COLLECTED (PAID)" value={peso(paidRev)} />
        <Stat label="STILL DUE" value={peso(dueRev)} />
      </div>

      <h4 style={S.repSection}>Per Barber</h4>
      <div style={S.list}>
        {byBarber.map((b) => (
          <div key={b.name} style={S.repBarberRow}>
            <span style={S.repBarberName}>{b.name}</span>
            <div style={S.repBar}><div style={{ ...S.repBarFill, width: `${(b.rev / maxBarberRev) * 100}%` }} /></div>
            <span style={S.repBarberStat}>{b.count} cuts · {peso(b.rev)}</span>
          </div>
        ))}
      </div>

      <h4 style={S.repSection}>Top Services</h4>
      <div style={S.list}>
        {topServices.length === 0 ? <div style={S.empty}>No bookings in this period.</div> :
          topServices.map(([name, c]) => (
            <div key={name} style={S.listItem}><span style={S.listName}>{name}</span><span style={S.repCount}>{c}×</span></div>
          ))}
      </div>
      <p style={{ marginTop: 16, fontSize: 11, color: GREY, lineHeight: 1.5 }}>Periods are measured back from now (last 24h / 7 days / 30 days) using each booking's creation time.</p>
    </div>
  );
}

// ─── Payments tab (toggle + edit methods + reservation fee) ───────
function PaymentsTab({ payments, setPayments, fee, setFee, peso }) {
  const [draft, setDraft] = useState(payments);
  const [feeDraft, setFeeDraft] = useState(fee);
  const [savedFlash, setSavedFlash] = useState(false);
  useEffect(() => { setDraft(payments); }, [payments]);
  useEffect(() => { setFeeDraft(fee); }, [fee]);
  const dirty = JSON.stringify(draft) !== JSON.stringify(payments) || JSON.stringify(feeDraft) !== JSON.stringify(fee);

  const toggle = (k) => setDraft({ ...draft, [k]: { ...draft[k], on: !draft[k].on } });
  const edit = (k, field, val) => setDraft({ ...draft, [k]: { ...draft[k], [field]: val } });
  const save = () => { setPayments(draft); setFee(feeDraft); setSavedFlash(true); setTimeout(() => setSavedFlash(false), 2000); };
  const discard = () => { setDraft(payments); setFeeDraft(fee); };

  const fields = {
    gcash: [["name", "Account Name"], ["number", "Mobile Number"]],
    bank: [["bankName", "Bank"], ["accName", "Account Name"], ["accNumber", "Account Number"]],
    crypto: [["network", "Network (e.g. USDT TRC20)"], ["address", "Wallet Address"]],
    cash: [],
  };
  return (
    <div style={S.manageWrap}>
      <h3 style={S.manageTitle}>Payment Methods</h3>
      <p style={S.manageSub}>Toggle which methods customers see at checkout and edit the details. Make your changes, then tap <strong>Save Changes</strong>.</p>

      {/* Reservation fee */}
      <div style={{ ...S.payCard, borderColor: GOLD }}>
        <div style={S.payCardHead}>
          <span style={S.payCardTitle}>💺 Online Reservation Fee</span>
          <button style={{ ...S.switch, background: feeDraft.on ? "#5ec46a" : "#444" }} onClick={() => setFeeDraft({ ...feeDraft, on: !feeDraft.on })}>
            <span style={{ ...S.knob, transform: feeDraft.on ? "translateX(20px)" : "translateX(0)" }} />
          </button>
        </div>
        <p style={S.gcashEditNote}>Added on top of the service price for online bookings. Walk-ins pay no fee.</p>
        {feeDraft.on && (
          <div style={S.editRow}>
            <span style={S.editLabel}>Fee amount (₱)</span>
            <input style={{ ...S.editInput, maxWidth: 120 }} type="number" value={feeDraft.amount} onChange={(e) => setFeeDraft({ ...feeDraft, amount: parseInt(e.target.value || "0", 10) })} />
          </div>
        )}
        {feeDraft.on && <p style={S.feePreview}>Example: a {peso(300)} service is billed {peso(300 + (feeDraft.amount || 0))} online ({peso(300)} + {peso(feeDraft.amount || 0)} fee).</p>}
      </div>

      {Object.keys(draft).map((k) => (
        <div key={k} style={S.payCard}>
          <div style={S.payCardHead}>
            <span style={S.payCardTitle}>{draft[k].label}</span>
            <button style={{ ...S.switch, background: draft[k].on ? "#5ec46a" : "#444" }} onClick={() => toggle(k)}>
              <span style={{ ...S.knob, transform: draft[k].on ? "translateX(20px)" : "translateX(0)" }} />
            </button>
          </div>
          {k === "gcash" && <p style={S.gcashEditNote}>QR is set from your uploaded InstaPay code. Edit name/number below.</p>}
          {fields[k].map(([f, lbl]) => (
            <div key={f} style={S.editRow}>
              <span style={S.editLabel}>{lbl}</span>
              <input style={S.editInput} value={draft[k][f] || ""} onChange={(e) => edit(k, f, e.target.value)} />
            </div>
          ))}
          {k === "crypto" && <p style={S.cryptoWarn}>Note: crypto suits few walk-in customers and prices are volatile. Toggle off if unused.</p>}
        </div>
      ))}

      <div style={S.saveBar}>
        <span style={S.saveStatus}>
          {savedFlash ? <span style={{ color: "#5ec46a", fontWeight: 700 }}>✓ Saved</span>
            : dirty ? <span style={{ color: GOLD, fontWeight: 700 }}>● Unsaved changes</span>
            : <span style={{ color: GREY }}>All changes saved</span>}
        </span>
        {dirty && <button style={S.discardBtn} onClick={discard}>Discard</button>}
        <button style={{ ...S.saveBtn, opacity: dirty ? 1 : 0.5, cursor: dirty ? "pointer" : "default" }} onClick={dirty ? save : undefined}>Save Changes</button>
      </div>
      <p style={S.testNote}>For testing, details save on this device. In the live version (after the backend is connected) they save permanently and securely.</p>
    </div>
  );
}

const Stat = ({ label, value }) => (<div style={S.stat}><div style={S.statVal}>{value}</div><div style={S.statLabel}>{label}</div></div>);

