const css = `
@import url('https://fonts.googleapis.com/css2?family=Anton&family=Archivo:wght@400;600;700;800&display=swap');
*{box-sizing:border-box;}
::-webkit-scrollbar{width:8px;height:8px;}
::-webkit-scrollbar-thumb{background:${GOLD};}
::-webkit-scrollbar-track{background:#111;}
li:hover .menuName{color:${GOLD};}
.typing{display:inline-flex;gap:4px;}
.typing i{width:7px;height:7px;background:${GOLD};animation:blink 1.2s infinite;}
.typing i:nth-child(2){animation-delay:.2s;}
.typing i:nth-child(3){animation-delay:.4s;}
@keyframes blink{0%,60%,100%{opacity:.2;}30%{opacity:1;}}
@keyframes pulse{0%,100%{opacity:1;}50%{opacity:.3;}}
@keyframes fade{from{opacity:0;}to{opacity:1;}}
`;
